#include<bits/stdc++.h>
#define int long long
#define MP make_pair
#define F first
#define S second
#define PA pair <int, int>
using namespace std;
int n;
int l,r;
int a[20];
const int M = 6000005;
int Next[M], ver[M], head[M];
int edge[M];
int d[M];
int vis[M];
int mod = 1e9;
int tot;
void add (int x, int y, int z) {
	Next[++tot] = head[x];
	head[x] = tot;
	ver[tot] = y;
	edge[tot] = z;
}
priority_queue <PA, vector <PA>, greater <PA> > q;
void dijkstra () {
	memset (d, 0x3f, sizeof (d));
	d[0] = 0;
	q.push (MP (d[0], 0));
	while (q.size()) {
		int x = q.top ().S;
		q.pop ();
		if (vis[x]) {
			continue;
		}
		vis[x] = 1;
		for (int i = head[x]; i; i = Next[i]) {
			int y = ver[i], z = edge[i];
			if (d[y] > d[x] + z) {
				d[y] = d[x] + z;
				q.push (MP (d[y], y));
			}
		}
	}
}
int ans;
int m;
signed main() {
	cin >> n >> l >> r;
	l--;
	for (int i = 1; i <= n; i++) {
		int x;
		cin >> x;
		if (x) {
			a[++m] = x;
		}
	}
	n = m;
	if (n == 0) {
		cout << 0;
		return 0;
	}
	sort (a + 1, a + n + 1);
	mod = a[1];
	for (int i = 1; i <= n; i++) {
		for (int j = 0; j < mod; j++) {
			if (a[i] != mod) {
				add (j, (j + a[i]) % mod, a[i]);
			}
		}
	}
	dijkstra ();
	for (int i = 0; i < mod; i++) {
		if (r >= d[i]) {
			ans += (r - d[i]) / mod + 1;
		}
		if (l >= d[i]) {
			ans -= (l - d[i]) / mod + 1;
		}
	}
	cout << ans;
	return 0;
}
